+/// Calculate safe GPU layers for imatrix generation based on model size
+fn calculateSafeGPULayers(model_size_gb: f32, system_memory_gb: f32) u32 {
+    // For imatrix generation, we need to be conservative to avoid OOM
+    // Formula: layers = (available_memory * 0.6) / layer_size
+    // Rough estimate: each layer ~= model_size / 64 layers (typical for large models)
+
+    const available_memory = system_memory_gb * 0.75; // Use 75% of RAM
+    const estimated_layers = @as(f32, 64.0); // Assume 64 layers for 32B models
+    const layer_size = model_size_gb / estimated_layers;
+
+    const safe_layers = @as(u32, @intFromFloat(available_memory / layer_size * 0.5)); // 50% safety margin
+
+    // Cap at reasonable limits
+    if (model_size_gb > 20.0) {
+        return 0; // Very large models: CPU only
+    } else if (safe_layers < 8) {
+        return 0; // Too few layers, not worth GPU overhead
+    } else {
+        return @min(safe_layers, 32); // Max 32 layers to GPU
+    }
+}
+
+/// Get system memory in GB
